class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        print(f"{self.name} makes a sound")

class Dog(Animal):
    def bark(self):
        print(f"{self.name} says: Woof!")

# Dog has Animal's methods + its own
fido = Dog("Fido")
fido.speak()  # From Animal
fido.bark()   # From Dog

class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        print(f"{self.name} makes a sound")

class Dog(Animal):
    def speak(self):  # Override
        print(f"{self.name} barks: Woof!")

class Cat(Animal):
    def speak(self):  # Override
        print(f"{self.name} meows: Meow!")

animals = [Dog("Fido"), Cat("Whiskers")]
for animal in animals:
    animal.speak()

class Animal:
    def __init__(self, name):
        self.name = name

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)  # Call parent __init__
        self.breed = breed

fido = Dog("Fido", "Beagle")
print(f"Name: {fido.name}")   # From Animal
print(f"Breed: {fido.breed}") # From Dog
